import { Hono } from 'hono'
import { cors } from 'hono/cors'
import { logger } from 'hono/logger'
import { agentRoutes } from './routes/agents'
import { missionRoutes } from './routes/missions'

const app = new Hono()

app.use('*', cors({ origin: 'http://localhost:5173' }))
app.use('*', logger())

app.route('/api/agents', agentRoutes)
app.route('/api/missions', missionRoutes)

app.get('/health', (c) => c.json({ status: 'ok', time: new Date().toISOString() }))

// WebSocket hub — agent output streams
const clients = new Set<WebSocket>()

app.get('/ws', (c) => {
  const { response, socket } = Bun.upgradeWebSocket(c.req.raw)!
  return response
})

export function broadcast(event: string, data: unknown) {
  const msg = JSON.stringify({ event, data, ts: Date.now() })
  for (const ws of clients) {
    if (ws.readyState === WebSocket.OPEN) ws.send(msg)
  }
}

const server = Bun.serve({
  port: 3001,
  fetch: app.fetch,
  websocket: {
    open(ws) { clients.add(ws.raw as WebSocket) },
    close(ws) { clients.delete(ws.raw as WebSocket) },
    message() {}
  }
})

console.log(`ClawCorp server running on http://localhost:${server.port}`)

